// Generated by OrchestKit Claude Plugin
// Created: 2026-07-10

/**
 * Telemetry Dark-State Check — SessionStart Hook (#2590)
 *
 * `bin/telemetry-sync.mjs` posts local telemetry (.claude/telemetry/*.jsonl) to
 * $ORCHESTKIT_HOOK_URL, and only DELETES rotated files after a successful POST.
 * Its guard is `if (!hookUrl || !hookToken) { log; exit 0 }` — so when a user
 * has clearly INTENDED to sync (they set $ORCHESTKIT_HOOK_TOKEN) but the URL is
 * missing, sync silently no-ops: nothing is uploaded, rotated .jsonl files are
 * never cleaned, and events.jsonl grows unbounded. The only signal is one line
 * of stdout from a rarely-run CLI — a fail-silent dark state (#2590).
 *
 * This hook closes that class the same way #1860 (hook-token-check) handles the
 * inverse (URL/entries set, TOKEN unset): at SessionStart, if $ORCHESTKIT_HOOK_TOKEN
 * is set AND $ORCHESTKIT_HOOK_URL is unset AND local telemetry is actually
 * accumulating, emit a single stderr banner naming the dir + backlog size.
 *
 * Deliberately NOT fired for the default local-only mode (neither var set) —
 * OrchestKit is a public plugin and keeping telemetry local is the correct,
 * common default; warning every user would be pure noise. The TOKEN-set gate
 * targets only the partial-configuration misconfig.
 *
 * Opt-out: ORK_NO_TELEMETRY_DARK_WARN=1.
 *
 * Cost: one readdir + statSync per .jsonl, ~1-3ms on SSD. Async — non-blocking.
 *
 * Hook event: SessionStart
 */

import { existsSync, readdirSync, statSync } from 'node:fs';
import { join } from 'node:path';
import type { HookInput, HookResult, HookContext } from '../types.js';
import { outputSilentSuccess } from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';

const HOOK_NAME = 'lifecycle/telemetry-dark-check';
const URL_ENV_VAR = 'ORCHESTKIT_HOOK_URL';
const TOKEN_ENV_VAR = 'ORCHESTKIT_HOOK_TOKEN';
const OPT_OUT_ENV_VAR = 'ORK_NO_TELEMETRY_DARK_WARN';

// Only warn once there is a non-trivial backlog, so a fresh/near-empty dir stays
// quiet even in the misconfigured state. 64 KiB ≈ a few hundred events.
const BACKLOG_WARN_BYTES = 64 * 1024;

interface Backlog {
  /** Absolute telemetry directory path. */
  dir: string;
  /** Number of .jsonl files present. */
  fileCount: number;
  /** Total bytes across all .jsonl files. */
  totalBytes: number;
}

/**
 * Resolve the telemetry directory the same way bin/telemetry-sync.mjs does:
 * CLAUDE_PLUGIN_DATA/telemetry when set, else <projectDir>/.claude/telemetry.
 * Guards against JSON leaking into CLAUDE_PROJECT_DIR from hook stdout (#1250).
 */
function resolveTelemetryDir(projectDir: string | undefined): string | null {
  const pluginData = process.env.CLAUDE_PLUGIN_DATA;
  if (pluginData) return join(pluginData, 'telemetry');

  const raw = projectDir || process.env.CLAUDE_PROJECT_DIR;
  if (!raw || raw.startsWith('{') || raw.startsWith('[')) return null;
  return join(raw, '.claude', 'telemetry');
}

/** Sum size + count of .jsonl telemetry files in the dir. */
function measureBacklog(dir: string): Backlog | null {
  if (!existsSync(dir)) return null;

  let entries: string[];
  try {
    entries = readdirSync(dir);
  } catch {
    return null;
  }

  let fileCount = 0;
  let totalBytes = 0;
  for (const name of entries) {
    if (!name.endsWith('.jsonl')) continue;
    try {
      const st = statSync(join(dir, name));
      if (st.isFile()) {
        fileCount += 1;
        totalBytes += st.size;
      }
    } catch {
      // File vanished mid-scan (rotation) — skip.
    }
  }

  if (fileCount === 0) return null;
  return { dir, fileCount, totalBytes };
}

/** Compose the operator-facing warning with actionable scope. */
function formatWarning(backlog: Backlog): string {
  const kib = Math.round(backlog.totalBytes / 1024);
  return (
    `[orchestkit] WARN: $${TOKEN_ENV_VAR} is set but $${URL_ENV_VAR} is unset — ` +
    `telemetry-sync silently no-ops. ${backlog.fileCount} local telemetry ` +
    `file(s) (~${kib} KiB) are accumulating in ${backlog.dir} and rotated files ` +
    `will never be cleaned. Fix: export ${URL_ENV_VAR}=<ingest-url> (then restart ` +
    `this session), or unset ${TOKEN_ENV_VAR} to stay local-only. ` +
    `Silence: ${OPT_OUT_ENV_VAR}=1. See #2590.`
  );
}

export function telemetryDarkCheck(
  input: HookInput,
  ctx: HookContext = NOOP_CTX,
): HookResult {
  if (process.env[OPT_OUT_ENV_VAR] === '1') return outputSilentSuccess();

  const token = process.env[TOKEN_ENV_VAR];
  const url = process.env[URL_ENV_VAR];

  // Only the partial-config misconfig: intent-to-sync (token) but no URL.
  // Neither-set (default local-only) and both-set (healthy) stay silent.
  const tokenSet = typeof token === 'string' && token.trim().length > 0;
  const urlSet = typeof url === 'string' && url.trim().length > 0;
  if (!tokenSet || urlSet) return outputSilentSuccess();

  if (!input || typeof input !== 'object') return outputSilentSuccess();
  const projectDir = input.project_dir || ctx.projectDir;

  const dir = resolveTelemetryDir(projectDir);
  if (!dir) return outputSilentSuccess();

  const backlog = measureBacklog(dir);
  if (!backlog || backlog.totalBytes < BACKLOG_WARN_BYTES) {
    return outputSilentSuccess();
  }

  process.stderr.write(`${formatWarning(backlog)}\n`);
  ctx.log(
    HOOK_NAME,
    `Flagged dark telemetry backlog: ${backlog.fileCount} file(s), ${backlog.totalBytes} bytes in ${backlog.dir}`,
  );

  return outputSilentSuccess();
}

// Export internals for unit testing only — not part of the public hook API.
export const _internals = {
  URL_ENV_VAR,
  TOKEN_ENV_VAR,
  OPT_OUT_ENV_VAR,
  BACKLOG_WARN_BYTES,
  resolveTelemetryDir,
  measureBacklog,
  formatWarning,
};
