/**
 * Session Heartbeat Finalizer — SessionEnd Hook (#1885).
 *
 * Companion to session-heartbeat-publisher. On graceful session end,
 * marks status=completed in the cross-session state file so other
 * sessions can distinguish "still running" from "ran to clean end".
 *
 * The publisher writes status='running' on every structural event.
 * The finalizer writes status='completed' once, at SessionEnd.
 * If the session is killed without SessionEnd firing (terminal close,
 * OOM), status will stay at 'running' but last_heartbeat will go stale
 * — readers should treat (running AND last_heartbeat > N min ago) as
 * effectively stopped.
 *
 * Never blocks. Best-effort write.
 */

import type { HookInput, HookResult, HookContext } from '../types.js';
import { outputSilentSuccess } from '../lib/common.js';
import { getProjectDir } from '../lib/paths.js';
import { NOOP_CTX } from '../lib/context.js';
import {
  getStateFilePath,
  readSessionState,
  writeSessionStateAtomic,
  mergeSessionState,
  repoSlugFromCwd,
} from '../lib/session-state.js';

const HOOK_NAME = 'session-heartbeat-finalizer';

export function sessionHeartbeatFinalizer(
  input: HookInput,
  ctx: HookContext = NOOP_CTX,
): HookResult {
  const cwd = getProjectDir();
  if (!cwd) return outputSilentSuccess();

  const repo = repoSlugFromCwd(cwd);
  const sessionId = input.session_id;
  if (!sessionId) return outputSilentSuccess();

  const path = getStateFilePath(repo, sessionId);
  const existing = readSessionState(path);
  // Only write if the publisher already created a file. We don't want to
  // create empty state files for sessions that never did structural work
  // — that would just produce noise for readers.
  if (!existing) {
    ctx.log(HOOK_NAME, `Skip finalize: no prior state for ${repo}/${sessionId}`, 'debug');
    return outputSilentSuccess();
  }

  const next = mergeSessionState(existing, { status: 'completed' }, repo, sessionId);
  const wrote = writeSessionStateAtomic(path, next);
  if (wrote) {
    ctx.log(HOOK_NAME, `Finalized state for ${repo}/${sessionId}`, 'debug');
  } else {
    ctx.log(HOOK_NAME, `Failed to finalize state for ${repo}/${sessionId}`, 'warn');
  }

  return outputSilentSuccess();
}

export default sessionHeartbeatFinalizer;
