/**
 * Goal Budget Guard — SessionEnd Hook (M140 G5 #1791)
 *
 * Cost circuit-breaker for `/goal`. Reads ended `/goal` runs from
 * `.claude/state/goal-history.jsonl` for this session, sums their turn_count
 * and ended_token_estimate, and writes
 * `.claude/state/goal-budget-tripped.json` if either ceiling is breached.
 *
 * Defaults:
 *   - ORK_GOAL_MAX_TURNS_PER_SESSION  = 30
 *   - ORK_GOAL_MAX_TOKENS_PER_SESSION = 250_000
 *
 * The companion `prompt/goal-tracker` reads the brake file and refuses the
 * next `/goal` with `continueOnBlock: true` so the user can override.
 *
 * Async: write-side only, must not block session exit.
 */

import { existsSync, mkdirSync, readFileSync, writeFileSync } from 'node:fs';
import { dirname, join } from 'node:path';
import type { HookInput, HookResult, HookContext } from '../types.js';
import { outputSilentSuccess } from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';

const HOOK_NAME = 'lifecycle/goal-budget-guard';
const HISTORY_REL = join('.claude', 'state', 'goal-history.jsonl');
const BRAKE_REL = join('.claude', 'state', 'goal-budget-tripped.json');

const DEFAULT_MAX_TURNS = 30;
const DEFAULT_MAX_TOKENS = 250_000;

interface HistoryEntry {
  session_id?: string;
  ended_at?: string | null;
  ended_token_estimate?: number;
  turn_count?: number;
}

interface SessionTotals {
  turns: number;
  tokens: number;
}

/** Sum closed `/goal` runs for sessionId. */
export function sumSessionUsage(
  contents: string,
  sessionId: string,
): SessionTotals {
  let turns = 0;
  let tokens = 0;
  for (const line of contents.split(/\r?\n/)) {
    if (!line.trim()) continue;
    let parsed: HistoryEntry;
    try {
      parsed = JSON.parse(line);
    } catch {
      continue;
    }
    if (parsed.session_id !== sessionId) continue;
    if (!parsed.ended_at) continue;
    turns += typeof parsed.turn_count === 'number' ? parsed.turn_count : 0;
    tokens +=
      typeof parsed.ended_token_estimate === 'number'
        ? parsed.ended_token_estimate
        : 0;
  }
  return { turns, tokens };
}

function readNumberEnv(name: string, fallback: number): number {
  const raw = process.env[name];
  if (!raw) return fallback;
  const n = Number(raw);
  return Number.isFinite(n) && n > 0 ? n : fallback;
}

export function goalBudgetGuard(
  input: HookInput,
  ctx: HookContext = NOOP_CTX,
): HookResult {
  const sessionId = input.session_id || ctx.sessionId || 'unknown';
  const projectDir = ctx.projectDir;
  const historyPath = join(projectDir, HISTORY_REL);

  if (!existsSync(historyPath)) {
    return outputSilentSuccess();
  }

  let raw: string;
  try {
    raw = readFileSync(historyPath, 'utf8');
  } catch (err) {
    ctx.log(
      HOOK_NAME,
      `read failed: ${err instanceof Error ? err.message : String(err)}`,
      'warn',
    );
    return outputSilentSuccess();
  }

  const totals = sumSessionUsage(raw, sessionId);
  const maxTurns = readNumberEnv('ORK_GOAL_MAX_TURNS_PER_SESSION', DEFAULT_MAX_TURNS);
  const maxTokens = readNumberEnv(
    'ORK_GOAL_MAX_TOKENS_PER_SESSION',
    DEFAULT_MAX_TOKENS,
  );

  let reason: 'turns_cap' | 'tokens_cap' | null = null;
  if (totals.turns >= maxTurns) reason = 'turns_cap';
  else if (totals.tokens >= maxTokens) reason = 'tokens_cap';

  if (!reason) {
    ctx.log(
      HOOK_NAME,
      `under budget: turns=${totals.turns}/${maxTurns} tokens=${totals.tokens}/${maxTokens}`,
      'debug',
    );
    return outputSilentSuccess();
  }

  const brakePath = join(projectDir, BRAKE_REL);
  try {
    mkdirSync(dirname(brakePath), { recursive: true });
    writeFileSync(
      brakePath,
      JSON.stringify(
        {
          tripped_at: new Date().toISOString(),
          session_id: sessionId,
          turns: totals.turns,
          tokens: totals.tokens,
          reason,
        },
        null,
        2,
      ),
    );
    ctx.log(
      HOOK_NAME,
      `BRAKE tripped: reason=${reason} turns=${totals.turns} tokens=${totals.tokens}`,
      'warn',
    );
  } catch (err) {
    ctx.log(
      HOOK_NAME,
      `failed to write brake: ${err instanceof Error ? err.message : String(err)}`,
      'warn',
    );
  }

  return outputSilentSuccess();
}
