/**
 * PreCompact Task-Done Prompt — Issue #1469 (extended by M119 dogfood cluster)
 *
 * Blocks compact when ALL of:
 *   - Imminent zone reached (#1480, default ~85% of CLAUDE_MAX_CONTEXT)
 *   - >= 2 of 3 signals match: gitQuiet, quiescent, breakpoint commit subject
 *   - 30-min cooldown elapsed since last fire
 *   - Not opted out (ORK_NO_PRECOMPACT_PROMPT)
 *
 * On fire: stopReason adapts to cache heat (#1479) and a per-session
 * nudge-outcome marker is written (#1476) for downstream resolvers.
 *
 * Source for breakpoint signal swapped from decisions.jsonl to git log -1
 * commit subject (#1477) — universal and tied to actual repo state.
 */

import { existsSync, readFileSync, mkdirSync, appendFileSync } from 'node:fs';
import { execFileSync } from 'node:child_process';
import { join, dirname } from 'node:path';
import type { HookInput, HookResult, HookContext } from '../types.js';
import { outputSilentSuccess, getProjectDir, getSessionId } from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';
import {
  loadAccumStateOrNull,
  isInImminentZone,
  evaluateCacheHeat,
  type AccumState,
} from '../lib/session-token-accum.js';
import { matchesBreakpoint } from '../lib/breakpoint-keywords.js';
import { writeMarker } from '../lib/nudge-outcome-state.js';

const HOOK_NAME = 'pre-compact-task-done-prompt';
const COOLDOWN_MS = 30 * 60 * 1000;
const QUIESCENT_WINDOW_MS = 5 * 60 * 1000;
const MAX_DIRTY_FILES = 2;

interface TelemetryEntry {
  timestamp: string;
  fired: boolean;
  signals: { gitQuiet: boolean; quiescent: boolean; breakpointKeywords: boolean };
  cooldown?: boolean;
  optOut?: boolean;
  belowImminentZone?: boolean;
  cacheHeat?: 'hot' | 'neutral';
}

function readLastLines(path: string, n: number): string[] {
  if (!existsSync(path)) return [];
  try {
    const content = readFileSync(path, 'utf8').trim();
    if (!content) return [];
    return content.split('\n').filter(Boolean).slice(-n);
  } catch {
    return [];
  }
}

function gitQuiet(projectDir: string): boolean {
  try {
    const out = execFileSync('git', ['diff', '--name-only', 'HEAD'], {
      encoding: 'utf8',
      timeout: 2000,
      cwd: projectDir,
      stdio: ['pipe', 'pipe', 'pipe'],
      windowsHide: true,
    });
    const n = out.trim().split('\n').filter(Boolean).length;
    return n <= MAX_DIRTY_FILES;
  } catch {
    return false;
  }
}

function isQuiescent(projectDir: string): boolean {
  const path = join(projectDir, '.claude', 'logs', 'subagent-spawns.jsonl');
  if (!existsSync(path)) return false;
  const lines = readLastLines(path, 10);
  if (lines.length === 0) return false;
  const cutoff = Date.now() - QUIESCENT_WINDOW_MS;
  for (const line of lines) {
    try {
      const entry = JSON.parse(line);
      if (typeof entry.timestamp === 'string') {
        const ts = new Date(entry.timestamp).getTime();
        if (Number.isFinite(ts) && ts > cutoff) return false;
      }
    } catch {
      // ignore unparseable
    }
  }
  return true;
}

/** #1477 — read last commit subject and check against keyword list. */
function hasBreakpointKeyword(projectDir: string): boolean {
  try {
    const subject = execFileSync('git', ['log', '-1', '--format=%s'], {
      encoding: 'utf8',
      timeout: 2000,
      cwd: projectDir,
      stdio: ['pipe', 'pipe', 'pipe'],
      windowsHide: true,
    }).trim();
    return matchesBreakpoint(subject);
  } catch {
    return false;
  }
}

function lastFireTimestamp(telemetryPath: string): number {
  const lines = readLastLines(telemetryPath, 20);
  for (let i = lines.length - 1; i >= 0; i--) {
    try {
      const entry = JSON.parse(lines[i]) as TelemetryEntry;
      if (entry.fired) {
        const ts = new Date(entry.timestamp).getTime();
        if (Number.isFinite(ts)) return ts;
      }
    } catch {
      // skip
    }
  }
  return 0;
}

function appendTelemetry(path: string, entry: TelemetryEntry): void {
  try {
    mkdirSync(dirname(path), { recursive: true });
    appendFileSync(path, `${JSON.stringify(entry)}\n`);
  } catch {
    // best-effort
  }
}

function buildStopReason(state: AccumState | null): string {
  const heat = state ? evaluateCacheHeat(state) : 'neutral';
  if (heat === 'hot' && state) {
    return (
      'Compact paused — task looks wrapped up. Your prompt cache is warm ' +
      `(${state.cacheReadTokens.toLocaleString('en-US')} cache-read tokens accumulated). ` +
      'Consider /compact to keep that warm cache, or /clear if switching projects.'
    );
  }
  return (
    'Compact paused — task looks wrapped up. Type /clear for a fresh session ' +
    '(zero context cost) or /compact to keep history and continue.'
  );
}

export function preCompactTaskDonePrompt(
  _input: HookInput,
  ctx: HookContext = NOOP_CTX,
): HookResult {
  const projectDir = ctx.projectDir || getProjectDir();
  const sessionId = ctx.sessionId || getSessionId();
  const telemetry = join(projectDir, '.claude', 'telemetry', 'pre-compact-decisions.jsonl');
  const now = Date.now();
  const noSignals = { gitQuiet: false, quiescent: false, breakpointKeywords: false };

  if (process.env.ORK_NO_PRECOMPACT_PROMPT === '1') {
    appendTelemetry(telemetry, {
      timestamp: new Date(now).toISOString(),
      fired: false,
      signals: noSignals,
      optOut: true,
    });
    return outputSilentSuccess();
  }

  const last = lastFireTimestamp(telemetry);
  if (last > 0 && now - last < COOLDOWN_MS) {
    appendTelemetry(telemetry, {
      timestamp: new Date(now).toISOString(),
      fired: false,
      signals: noSignals,
      cooldown: true,
    });
    ctx.log(HOOK_NAME, `skipped — cooldown (last fire ${Math.round((now - last) / 60000)}m ago)`);
    return outputSilentSuccess();
  }

  // #1480 — gate on imminent zone before running the heuristic
  const state = loadAccumStateOrNull(projectDir, sessionId);
  if (!isInImminentZone(state)) {
    appendTelemetry(telemetry, {
      timestamp: new Date(now).toISOString(),
      fired: false,
      signals: noSignals,
      belowImminentZone: true,
    });
    ctx.log(HOOK_NAME, `silent — below imminent zone (est ${state?.estimatedTokens ?? 'unknown'})`);
    return outputSilentSuccess();
  }

  const signals = {
    gitQuiet: gitQuiet(projectDir),
    quiescent: isQuiescent(projectDir),
    breakpointKeywords: hasBreakpointKeyword(projectDir),
  };
  const fire =
    Number(signals.gitQuiet) + Number(signals.quiescent) + Number(signals.breakpointKeywords) >= 2;
  const cacheHeat = state ? evaluateCacheHeat(state) : 'neutral';

  appendTelemetry(telemetry, {
    timestamp: new Date(now).toISOString(),
    fired: fire,
    signals,
    cacheHeat,
  });

  if (!fire) {
    ctx.log(
      HOOK_NAME,
      `silent — gitQuiet=${signals.gitQuiet} quiescent=${signals.quiescent} kws=${signals.breakpointKeywords}`,
    );
    return outputSilentSuccess();
  }

  // #1476 — drop nudge marker for downstream resolvers
  writeMarker(projectDir, sessionId, new Date(now).toISOString());

  ctx.log(HOOK_NAME, `blocking compact — task-done detected (cacheHeat=${cacheHeat})`);

  return {
    continue: false,
    decision: 'block',
    stopReason: buildStopReason(state),
  };
}

export default preCompactTaskDonePrompt;
