/**
 * FileChanged Hook — React to watched file modifications
 *
 * CC 2.1.83: Fires when a file in the watchPaths list changes.
 * Injects notification context so the model knows a config/rule changed.
 *
 * Watch list is set by SessionStart and CwdChanged hooks returning
 * watchPaths arrays.
 *
 * @hook FileChanged
 * @since CC 2.1.83
 * @see #1230
 */

import type { HookInput, HookResult , HookContext} from '../types.js';
import { outputSilentSuccess, outputWithContext } from '../lib/common.js';
// outputWithContext used in describeChange path
import { basename } from 'node:path';
import { NOOP_CTX } from '../lib/context.js';

const HOOK_NAME = 'file-changed';

/** Map file patterns to human-readable descriptions */
function describeChange(filePath: string, fileName: string): string | null {
  if (fileName === 'CLAUDE.md') {
    return 'Project instructions (CLAUDE.md) were modified. Re-read for updated rules.';
  }
  if (fileName === 'package.json') {
    return 'Dependencies (package.json) were modified. Check for new/removed packages.';
  }
  if (fileName === '.env' || fileName.startsWith('.env.')) {
    return 'Environment configuration (.env) was modified. Note: secrets are not loaded into context.';
  }
  if (filePath.includes('.claude/rules')) {
    return `Rules file (${fileName}) was modified. Updated rules are now active.`;
  }
  if (fileName === 'settings.json' && filePath.includes('.claude/')) {
    return 'Claude Code settings were modified. Changes take effect on next tool call.';
  }
  return null;
}

export function fileChanged(input: HookInput, ctx: HookContext = NOOP_CTX): HookResult {
  const filePath = input.changed_file_path || '';
  const fileName = input.changed_file || basename(filePath);

  if (!filePath) {
    return outputSilentSuccess();
  }

  ctx.log(HOOK_NAME, `Watched file changed: ${filePath}`);

  const description = describeChange(filePath, fileName);
  if (!description) {
    return outputSilentSuccess();
  }

  return outputWithContext(`[FileChanged] ${description}`);
}
