/**
 * Hook Token Check — SessionStart Hook (#1860)
 *
 * `scripts/generate-http-hooks` writes 19 type:"http" hook entries into the
 * user's settings.local.json, each carrying `Authorization: Bearer
 * $ORCHESTKIT_HOOK_TOKEN`. When the env var is unset in the launching shell
 * every hook fires returns 401 and the user only sees on-screen
 * "PreToolUse:Bash hook error" spam — masking real errors (the cc-event
 * ingestion gap, see yonatan-hq/platform#3589).
 *
 * This hook closes the fail-silent class: at SessionStart, if any type:"http"
 * hook entry in either project-scoped (.claude/settings.local.json) or
 * user-scoped (~/.claude/settings.local.json) references $ORCHESTKIT_HOOK_TOKEN
 * AND the env var is absent/empty, emit a single stderr banner naming the
 * offending file and the count.
 *
 * Pairs with the generator's --write refusal (same issue, defense-in-depth).
 *
 * Cost: 2 file reads + JSON parse, ~3-5ms on SSD. Async — non-blocking.
 *
 * Hook event: SessionStart
 */

import { existsSync, readFileSync } from 'node:fs';
import { homedir } from 'node:os';
import { join } from 'node:path';
import type { HookInput, HookResult, HookContext } from '../types.js';
import { outputSilentSuccess } from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';

const HOOK_NAME = 'lifecycle/hook-token-check';
const TOKEN_ENV_VAR = 'ORCHESTKIT_HOOK_TOKEN';
const TOKEN_REFERENCE = `$${TOKEN_ENV_VAR}`;

interface HookEntry {
  type?: string;
  url?: string;
  headers?: Record<string, string>;
  allowedEnvVars?: string[];
}

interface SettingsLocal {
  hooks?: Record<string, HookEntry[]>;
}

interface ScanResult {
  /** Path to the settings file that referenced the token. */
  path: string;
  /** Number of type:http entries referencing $ORCHESTKIT_HOOK_TOKEN. */
  count: number;
}

/**
 * Parse a settings.local.json file and count HTTP hook entries that
 * reference $ORCHESTKIT_HOOK_TOKEN in either headers or allowedEnvVars.
 */
function scanSettingsFile(path: string): ScanResult | null {
  if (!existsSync(path)) return null;

  let parsed: SettingsLocal;
  try {
    const raw = readFileSync(path, 'utf8');
    parsed = JSON.parse(raw) as SettingsLocal;
  } catch {
    // Malformed JSON — not our problem to repair; skip silently.
    return null;
  }

  if (!parsed.hooks || typeof parsed.hooks !== 'object') return null;

  let count = 0;
  for (const entries of Object.values(parsed.hooks)) {
    if (!Array.isArray(entries)) continue;
    for (const entry of entries) {
      if (entry?.type !== 'http') continue;
      const headerValues = entry.headers ? Object.values(entry.headers) : [];
      const headerRefs = headerValues.some(
        (v) => typeof v === 'string' && v.includes(TOKEN_REFERENCE)
      );
      const allowedRefs = Array.isArray(entry.allowedEnvVars)
        ? entry.allowedEnvVars.includes(TOKEN_ENV_VAR)
        : false;
      if (headerRefs || allowedRefs) count += 1;
    }
  }

  if (count === 0) return null;
  return { path, count };
}

/**
 * Compose the operator-facing warning. Names every offending file and
 * the total entry count so the user has actionable scope.
 */
function formatWarning(scans: ScanResult[]): string {
  const total = scans.reduce((sum, s) => sum + s.count, 0);
  const paths = scans.map((s) => `${s.path} (${s.count})`).join(', ');
  return (
    `[orchestkit] WARN: $${TOKEN_ENV_VAR} is unset but ${total} type:http hook ` +
    `entr${total === 1 ? 'y' : 'ies'} reference it. CC will 401 on every hook ` +
    `fire and the on-screen error spam will mask real failures. Files: ${paths}. ` +
    `Fix: export ${TOKEN_ENV_VAR}=<token> (or persist in your shell init / ` +
    `1Password reference), then restart this CC session. See #1860.`
  );
}

export function hookTokenCheck(
  input: HookInput,
  ctx: HookContext = NOOP_CTX,
): HookResult {
  // Guard: token set → silent success, no scan needed.
  const tokenValue = process.env[TOKEN_ENV_VAR];
  if (tokenValue && tokenValue.trim().length > 0) {
    return outputSilentSuccess();
  }

  if (!input || typeof input !== 'object') return outputSilentSuccess();
  const projectDir = input.project_dir || ctx.projectDir;

  const candidates: string[] = [];
  if (projectDir) {
    candidates.push(join(projectDir, '.claude', 'settings.local.json'));
  }
  // User-scoped settings — where the generator's default --write lands.
  candidates.push(join(homedir(), '.claude', 'settings.local.json'));

  const scans: ScanResult[] = [];
  for (const path of candidates) {
    const result = scanSettingsFile(path);
    if (result) scans.push(result);
  }

  if (scans.length === 0) return outputSilentSuccess();

  const warning = formatWarning(scans);
  process.stderr.write(`${warning}\n`);
  ctx.log(
    HOOK_NAME,
    `Flagged ${scans.reduce((s, x) => s + x.count, 0)} http hook entries across ${scans.length} settings file(s)`,
  );

  return outputSilentSuccess();
}

