/**
 * Local JSONL Telemetry Sink — Writes sanitized hook events to disk.
 *
 * Provides a never-lose-data safety net alongside the HTTP webhook sink.
 * Every event forwarded by webhookForwarder is also appended to a local
 * JSONL file. Format matches the HTTP payload exactly so batch replay
 * (Phase 4) can POST lines directly.
 *
 * Process model: Each CC hook spawns a separate Node.js process via
 * run-hook.mjs. We use appendFile (async callback) — NOT createWriteStream
 * (process dies too fast) or appendFileSync (blocks event loop).
 *
 * Concurrency: Multiple hook processes may append concurrently. POSIX
 * guarantees atomic write() with O_APPEND for buffers ≤ PIPE_BUF (4096).
 * Sanitized payloads are ~1400 bytes max — well under the limit.
 *
 * Rotation: Deferred to SessionEnd via rotateTelemetryIfNeeded().
 * Cleanup: Rotated files older than 7 days are deleted on SessionEnd.
 *
 * #1258: Phase 2 of Telemetry Provider Architecture (M105).
 */

import { appendFile, stat, rename, readdir, unlink } from 'node:fs/promises';
import { existsSync, mkdirSync } from 'node:fs';
import { join } from 'node:path';
import { getPluginDataDir, getProjectDir } from './paths.js';
import { logHook } from './common.js';

const HOOK_NAME = 'telemetry-jsonl';
const MAX_FILE_BYTES = 10 * 1024 * 1024; // 10 MB
const MAX_AGE_DAYS = 7;
const ACTIVE_FILENAME = 'events.jsonl';

/**
 * Resolve the telemetry storage directory.
 * Prefers CLAUDE_PLUGIN_DATA (survives plugin updates), falls back to project-local.
 */
export function getTelemetryDir(): string {
  const pluginData = getPluginDataDir();
  if (pluginData) {
    return join(pluginData, 'telemetry');
  }
  return join(getProjectDir(), '.claude', 'telemetry');
}

/**
 * Get the active telemetry file path.
 */
export function getTelemetryPath(): string {
  return join(getTelemetryDir(), ACTIVE_FILENAME);
}

/**
 * Write a telemetry event to the local JSONL file.
 * Non-blocking: uses appendFile with callback. The Node.js event loop
 * keeps the process alive until the callback fires (proven pattern from
 * run-hook.mjs line 404).
 *
 * Silently no-ops if the directory can't be created.
 */
export function writeTelemetryEvent(payload: Record<string, unknown> | object): void {
  const dir = getTelemetryDir();

  // Ensure directory exists (sync — only runs once per process, fast)
  if (!existsSync(dir)) {
    try {
      mkdirSync(dir, { recursive: true, mode: 0o700 });
    } catch {
      return; // Can't create dir — skip silently
    }
  }

  const line = `${JSON.stringify(payload)}\n`;
  const filePath = getTelemetryPath();

  // Async append — non-blocking, process stays alive until cb fires
  appendFile(filePath, line, 'utf8').catch(() => {
    logHook(HOOK_NAME, `Failed to write telemetry event (non-blocking)`);
  });
}

/**
 * Rotate the active telemetry file if it exceeds MAX_FILE_BYTES.
 * Called from usageSummaryReporter on SessionEnd.
 *
 * Rotation: rename events.jsonl → events.YYYY-MM-DDTHHMMSS.jsonl
 * A new events.jsonl will be created on the next appendFile call.
 */
export async function rotateTelemetryIfNeeded(): Promise<void> {
  const filePath = getTelemetryPath();

  try {
    const stats = await stat(filePath);
    if (stats.size <= MAX_FILE_BYTES) return;

    const timestamp = new Date().toISOString().replace(/[-:.]/g, '').slice(0, 15);
    const rotatedPath = join(getTelemetryDir(), `events.${timestamp}.jsonl`);

    await rename(filePath, rotatedPath);
    logHook(HOOK_NAME, `Rotated telemetry: ${Math.round(stats.size / 1024)}KB → ${rotatedPath}`);
  } catch {
    // File doesn't exist or rename failed — fine, nothing to rotate
  }
}

/**
 * Clean up rotated telemetry files older than MAX_AGE_DAYS.
 * Called from usageSummaryReporter on SessionEnd.
 */
export async function cleanOldTelemetryFiles(): Promise<void> {
  const dir = getTelemetryDir();
  const cutoff = Date.now() - MAX_AGE_DAYS * 24 * 60 * 60 * 1000;

  try {
    const files = await readdir(dir);

    for (const file of files) {
      // Only clean rotated files (events.YYYYMMDDTHHMMSS.jsonl), never the active file
      if (file === ACTIVE_FILENAME || !file.startsWith('events.') || !file.endsWith('.jsonl')) {
        continue;
      }

      const filePath = join(dir, file);
      try {
        const stats = await stat(filePath);
        if (stats.mtimeMs < cutoff) {
          await unlink(filePath);
          logHook(HOOK_NAME, `Cleaned old telemetry: ${file}`);
        }
      } catch {
        // Individual file cleanup failure — skip
      }
    }
  } catch {
    // Directory doesn't exist — nothing to clean
  }
}
