/**
 * SessionStart Nudge-Outcome Resolver — Issue #1476
 *
 * Closes the feedback loop for the pre-compact-task-done-prompt nudge (#1469).
 * PostCompact records `outcome="compact"` in the same session — but `/clear`
 * starts a NEW session, so we detect "the user chose /clear" by the absence
 * of a PostCompact resolution on the prior session's marker.
 *
 *   < 24h since fire   →  user_action="clear"
 *   ≥ 24h since fire   →  user_action="ignored"
 *
 * Runs on SessionStart for every new session. Reads markers for OTHER session
 * IDs in `.claude/state/`, resolves them, deletes the marker file. Best-effort.
 */

import type { HookInput, HookResult, HookContext } from '../types.js';
import { outputSilentSuccess, getProjectDir, getSessionId } from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';
import {
  listForeignMarkers,
  appendOutcome,
  deleteMarker,
} from '../lib/nudge-outcome-state.js';

const HOOK_NAME = 'nudge-outcome-resolver';
const IGNORE_THRESHOLD_MS = 24 * 60 * 60 * 1000;

export function nudgeOutcomeResolver(
  _input: HookInput,
  ctx: HookContext = NOOP_CTX,
): HookResult {
  try {
    const projectDir = ctx.projectDir || getProjectDir();
    const sessionId = ctx.sessionId || getSessionId();
    const markers = listForeignMarkers(projectDir, sessionId);
    if (markers.length === 0) return outputSilentSuccess();

    const now = Date.now();
    let cleared = 0;
    let ignored = 0;

    for (const marker of markers) {
      const firedMs = new Date(marker.firedAt).getTime();
      if (!Number.isFinite(firedMs)) {
        deleteMarker(projectDir, marker.sessionId);
        continue;
      }
      const ageMs = now - firedMs;
      const action: 'clear' | 'ignored' = ageMs >= IGNORE_THRESHOLD_MS ? 'ignored' : 'clear';
      appendOutcome(projectDir, {
        timestamp: new Date(now).toISOString(),
        type: 'outcome',
        user_action: action,
        nudge_fired_at: marker.firedAt,
        nudge_session_id: marker.sessionId,
        age_ms: ageMs,
      });
      deleteMarker(projectDir, marker.sessionId);
      if (action === 'clear') cleared++;
      else ignored++;
    }

    if (cleared || ignored) {
      ctx.log(HOOK_NAME, `resolved ${cleared} clear + ${ignored} ignored nudges from prior sessions`);
    }
  } catch {
    // best-effort
  }
  return outputSilentSuccess();
}

export default nudgeOutcomeResolver;
