/**
 * Ask-Fallback Injector — SessionStart Hook (#1795)
 *
 * When the user sets `ORK_ASK_FALLBACK=text`, the AskUserQuestion picker
 * is treated as unavailable and the model is instructed to fall back to
 * inline text prompts ("reply with 1/2/3/4").
 *
 * Motivation: CC 2.1.139 had a bug where the picker UI rendered but did
 * not accept keystrokes — Enter/arrows did nothing, only Esc dismissed.
 * Result: every AskUserQuestion auto-resolved to "User declined to answer
 * questions", silently breaking skills like brainstorm/fix-issue/create-pr.
 *
 * Migrated from UserPromptSubmit → SessionStart in M104 PR-A (#1234 audit
 * follow-up): the env var doesn't change mid-session, so injecting the
 * reminder once at SessionStart pins it to the cached system-prompt prefix
 * instead of paying the ~200-token cost on every prompt turn. Allow-listed
 * by hooks/bin/output-guard.mjs after #1822.
 *
 * Hook event: SessionStart (async, timeout: 5s)
 * Cost: single env-var read at session boot, no I/O, ~200 bytes injection.
 */

import type { HookInput, HookResult, HookContext } from '../types.js';
import { outputSilentSuccess, outputSessionStartContext } from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';

const HOOK_NAME = 'lifecycle/ask-fallback-injector';

const FALLBACK_REMINDER =
  '<system-reminder>\n' +
  '[ORK_ASK_FALLBACK=text] The AskUserQuestion picker is disabled this session ' +
  '(CC 2.1.139 input bug — see orchestkit#1795). Do not call AskUserQuestion. ' +
  'Instead, pose options inline as a numbered list and ask the user to reply ' +
  'with the number of their choice. Example:\n\n' +
  '  > Which auth strategy?\n' +
  '  >   1. JWT (stateless, no revoke)\n' +
  '  >   2. Session cookies (server-side store)\n' +
  '  >   3. OAuth-only (delegate to provider)\n' +
  '  > Reply with 1, 2, or 3.\n\n' +
  'Keep options to 2–4 to match picker affordances. Unset ORK_ASK_FALLBACK ' +
  'to restore picker mode once CC ships an upstream fix.\n' +
  '</system-reminder>';

export function askFallbackInjector(
  _input: HookInput,
  ctx: HookContext = NOOP_CTX,
): HookResult {
  if (process.env.ORK_ASK_FALLBACK !== 'text') {
    return outputSilentSuccess();
  }

  ctx.log(HOOK_NAME, 'ORK_ASK_FALLBACK=text — injecting text-prompt reminder (SessionStart, cached)');
  return outputSessionStartContext(FALLBACK_REMINDER);
}
