/**
 * TaskCreated Hook: Creation Tracker
 *
 * CC 2.1.84 TaskCreated event fires when a task is created via TaskCreate.
 * Logs creation events and enriches task context with branch/project metadata.
 *
 * @hook TaskCreated
 * @since CC 2.1.84
 */

import type { HookInput, HookResult , HookContext} from '../types.js';
import { appendEventLog } from '../lib/event-logger.js';
import { appendAnalytics, hashProject, getTeamContext } from '../lib/analytics.js';
import { NOOP_CTX } from '../lib/context.js';

export async function creationTracker(input: HookInput, ctx: HookContext = NOOP_CTX): Promise<HookResult> {
  if (!(ctx.projectDir)) {
    return { continue: true };
  }

  const taskId = input.task_id || 'unknown';
  const taskSubject = input.task_subject || '';
  const sessionId = input.session_id || '';

  appendEventLog('task-creations.jsonl', {
    timestamp: new Date().toISOString(),
    event: 'task_created',
    task_id: taskId,
    task_subject: taskSubject,
    session_id: sessionId,
  });

  // Cross-project task analytics
  appendAnalytics('task-usage.jsonl', {
    ts: new Date().toISOString(),
    pid: hashProject(process.env.CLAUDE_PROJECT_DIR || ''),
    event: 'created',
    task_subject: taskSubject,
    ...getTeamContext(),
  });

  return { continue: true };
}
