/**
 * Shared cryptographic and sanitization utilities for webhook payloads.
 *
 * signPayload(): HMAC-SHA256 signature for webhook authentication.
 * sanitizePayload(): Strips sensitive keys and truncates long values
 *   before payloads leave the machine. Prevents secret leakage via
 *   tool_input (Bash commands, env vars) and tool_output.
 *
 * Extracted from usage-summary-reporter.ts (#1257) to share across
 * webhookForwarder and usageSummaryReporter.
 */

import { createHmac } from 'node:crypto';

// Keys whose values should be redacted (case-insensitive substring match)
const SENSITIVE_KEYS = ['password', 'secret', 'token', 'key', 'credential', 'auth'];

// Patterns in string VALUES that indicate embedded secrets
const SECRET_VALUE_PATTERNS = [
  /sk-ant-[a-zA-Z0-9-]{20,}/,                  // Anthropic API keys (sk-ant-api03-...)
  /sk-[a-zA-Z0-9]{20,}/,                       // OpenAI API keys (sk-...)
  /ghp_[a-zA-Z0-9]{36,}/,                      // GitHub PATs
  /gho_[a-zA-Z0-9]{36,}/,                      // GitHub OAuth tokens
  /github_pat_[a-zA-Z0-9_]{60,}/,              // GitHub fine-grained PATs
  /xoxb-[a-zA-Z0-9-]{20,}/,                    // Slack bot tokens
  /xoxp-[a-zA-Z0-9-]{20,}/,                    // Slack user tokens
  /AKIA[A-Z0-9]{16}/,                          // AWS Access Key IDs
  /AIza[a-zA-Z0-9_-]{35}/,                    // Google/Firebase API keys
  /Bearer\s+[a-zA-Z0-9._-]{20,}/,             // Bearer tokens in headers
  /(?:export\s+\w*(?:KEY|TOKEN|SECRET|PASSWORD|CREDENTIAL)\w*\s*=\s*)([^\s;]+)/i, // env var assignments
  /(?:mongodb(?:\+srv)?:\/\/)[^\s]+/,           // MongoDB connection strings
  /(?:postgres(?:ql)?:\/\/)[^\s]+/,             // PostgreSQL connection strings
  /(?:mysql:\/\/)[^\s]+/,                       // MySQL connection strings
];

const MAX_STRING_LENGTH = 500;

/**
 * HMAC-SHA256 signature for webhook payload verification.
 * Format: sha256=<hex-digest>
 */
export function signPayload(body: string, secret: string): string {
  return `sha256=${createHmac('sha256', secret).update(body).digest('hex')}`;
}

/**
 * Redact a string value that contains embedded secrets.
 * Returns the original string if no secrets detected.
 */
function redactSecretValues(value: string): string {
  let result = value;
  for (const pattern of SECRET_VALUE_PATTERNS) {
    result = result.replace(pattern, (match) => {
      // Keep the prefix (export, Bearer, etc.) but redact the secret part
      const prefixEnd = match.search(/[a-zA-Z0-9._-]{20,}$/);
      if (prefixEnd > 0) {
        return `${match.slice(0, prefixEnd)}[REDACTED]`;
      }
      return '[REDACTED]';
    });
  }
  return result;
}

/**
 * Sanitize an object for safe transmission over the network.
 * - Redacts values of sensitive keys (password, secret, token, etc.)
 * - Detects and redacts embedded secrets in string values (API keys, Bearer tokens)
 * - Truncates long strings to MAX_STRING_LENGTH
 * - Recursively processes nested objects
 * - Returns undefined for undefined input (pass-through)
 */
export function sanitizePayload(
  obj: Record<string, unknown> | undefined
): Record<string, unknown> | undefined {
  if (!obj) return undefined;

  const sanitized: Record<string, unknown> = {};

  for (const [key, value] of Object.entries(obj)) {
    // Redact sensitive keys entirely
    if (SENSITIVE_KEYS.some(s => key.toLowerCase().includes(s))) {
      sanitized[key] = '[REDACTED]';
      continue;
    }

    // Process string values
    if (typeof value === 'string') {
      let processed = redactSecretValues(value);
      if (processed.length > MAX_STRING_LENGTH) {
        processed = `${processed.slice(0, MAX_STRING_LENGTH - 3)}...`;
      }
      sanitized[key] = processed;
      continue;
    }

    // Recursively sanitize nested objects
    if (typeof value === 'object' && value !== null && !Array.isArray(value)) {
      sanitized[key] = sanitizePayload(value as Record<string, unknown>);
      continue;
    }

    // Arrays: sanitize each element if object, pass through otherwise
    if (Array.isArray(value)) {
      sanitized[key] = value.map(item =>
        typeof item === 'object' && item !== null && !Array.isArray(item)
          ? sanitizePayload(item as Record<string, unknown>)
          : item
      );
      continue;
    }

    sanitized[key] = value;
  }

  return sanitized;
}
