/**
 * Telemetry Emitter — Grafana Echo-style pluggable sink architecture.
 *
 * Central emit() function fans out events to registered TelemetrySink
 * implementations. Each sink runs independently — one failing never
 * affects another. emit() itself NEVER throws.
 *
 * Sinks register at module scope (not SessionStart) because each CC
 * hook spawns a separate Node.js process. Module-scope registration
 * is deterministic and avoids race conditions with parallel hooks.
 *
 * Design stolen from:
 * - Grafana EchoBackend (supportedEvents filter + flush)
 * - Backstage AnalyticsApi (single captureEvent method)
 * - OTel BatchProcessor (drop on overflow, never block)
 *
 * #1259: Phase 3 of Telemetry Provider Architecture (M105).
 */

import type { HookInput } from '../types.js';
import { getSessionId, getCachedBranch, logHook } from './common.js';
import { sanitizePayload } from './crypto.js';
import { getProjectSlug } from '../lifecycle/usage-summary-reporter.js';

const HOOK_NAME = 'telemetry';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/**
 * Normalized telemetry event shape.
 * Matches the HTTP payload format so JSONL lines can be POSTed directly.
 */
export interface TelemetryEvent {
  event: string;
  session_id: string;
  project: string;
  timestamp: string;
  data: {
    tool_name?: string;
    tool_input?: Record<string, unknown>;
    tool_output?: Record<string, unknown>;
    tool_error?: string;
    agent_type?: string;
    agent_id?: string;
    parent_agent_id?: string;
  };
  metadata: {
    branch: string;
    source_channel: string;
    [key: string]: unknown;
  };
}

/**
 * Pluggable telemetry sink interface (Grafana Echo-style).
 *
 * - supportedEvents: empty array = all events. Non-empty = filter.
 * - addEvent: fire-and-forget. MUST NOT throw.
 * - flush: called on SessionEnd / SIGTERM. May be async.
 */
export interface TelemetrySink {
  readonly name: string;
  readonly supportedEvents: string[];
  addEvent(event: TelemetryEvent): void;
  flush(): Promise<void>;
}

// ---------------------------------------------------------------------------
// Sink Registry (module-scoped, per-process)
// ---------------------------------------------------------------------------

const sinks: TelemetrySink[] = [];

/**
 * Register a telemetry sink. Called at module scope by sink implementations.
 * Idempotent — duplicate names are silently ignored.
 */
export function registerSink(sink: TelemetrySink): void {
  if (sinks.some(s => s.name === sink.name)) return;
  sinks.push(sink);
}

/**
 * Get registered sink count (for testing).
 */
export function sinkCount(): number {
  return sinks.length;
}

/**
 * Clear all registered sinks (for testing only).
 */
export function _resetSinksForTesting(): void {
  sinks.length = 0;
}

// ---------------------------------------------------------------------------
// Emit
// ---------------------------------------------------------------------------

/**
 * Build a normalized TelemetryEvent from raw hook input.
 * Applies sanitization to tool_input and tool_output.
 */
export function buildEvent(input: HookInput): TelemetryEvent {
  return {
    // `||` not `??`: normalizeInput() guarantees a non-empty string today,
    // but this must independently guard '' too — a caller that bypasses
    // run-hook.mjs's normalization (a direct test, a future entry point)
    // would otherwise produce event:'' here, which is falsy but not
    // nullish, so `??` silently lets it through unfixed. See #2590.
    event: input.hook_event || 'unknown',
    session_id: input.session_id || getSessionId(),
    project: getProjectSlug(input),
    timestamp: new Date().toISOString(),
    data: {
      tool_name: input.tool_name || undefined,
      tool_input: sanitizePayload(input.tool_input as Record<string, unknown>) || undefined,
      tool_output: sanitizePayload(
        typeof input.tool_output === 'object' && input.tool_output !== null
          ? input.tool_output as Record<string, unknown>
          : input.tool_output ? { _raw: input.tool_output } : undefined
      ) || undefined,
      tool_error: input.tool_error || undefined,
      agent_type: input.agent_type || (input.tool_input as Record<string, unknown>)?.subagent_type as string || undefined,
      agent_id: input.agent_id || undefined,
      // CC 2.1.139: parent_agent_id for sub-agent trace stitching (Langfuse/Datadog)
      parent_agent_id: input.parent_agent_id || undefined,
    },
    metadata: {
      branch: getCachedBranch(),
      source_channel: 'orchestkit-forwarder',
      // CC 2.1.97: TRACEPARENT env var for cross-system trace correlation
      ...(process.env.TRACEPARENT ? { traceparent: process.env.TRACEPARENT } : {}),
    },
  };
}

/**
 * Emit a telemetry event to all registered sinks.
 *
 * - Builds normalized + sanitized event from raw hook input
 * - Fans out to all sinks whose supportedEvents match (or accept all)
 * - Each sink runs in its own try/catch — isolated failures
 * - NEVER throws — telemetry must not break hook execution
 * - Zero sinks registered = silent no-op (Grafana air-gapped pattern)
 */
export function emit(input: HookInput): void {
  if (sinks.length === 0) return;

  try {
    const event = buildEvent(input);

    for (const sink of sinks) {
      try {
        // Filter by supportedEvents (empty = accept all)
        if (sink.supportedEvents.length > 0 && !sink.supportedEvents.includes(event.event)) {
          continue;
        }
        sink.addEvent(event);
      } catch {
        logHook(HOOK_NAME, `Sink "${sink.name}" failed for ${event.event} (isolated)`);
      }
    }
  } catch {
    // Payload construction failed — silently drop
    logHook(HOOK_NAME, `Event construction failed (non-blocking)`);
  }
}

/**
 * Flush all registered sinks. Called on SessionEnd.
 * Each sink's flush runs independently — one failing doesn't block others.
 */
export async function flushAll(): Promise<void> {
  for (const sink of sinks) {
    try {
      await sink.flush();
    } catch {
      logHook(HOOK_NAME, `Flush failed for sink "${sink.name}" (non-blocking)`);
    }
  }
}
