/**
 * Handler 6: Smart Rule Suggestions
 *
 * Scans project signals (package.json, Dockerfile, .github/workflows) and
 * suggests missing .claude/rules/ files based on what the project uses.
 */

import { logHook } from '../lib/common.js';
import { existsSync, readFileSync } from 'node:fs';
import { basename, join } from 'node:path';
import { getProjectDir } from '../lib/paths.js';
import type { LoadedFile, ProjectSignal } from './types.js';

const HOOK_NAME = 'instructions-loaded/smart-suggestions';

export function smartRuleSuggestions(filesLoaded: LoadedFile[], _contents: Map<string, string>): string | null {
  const loadedNames = new Set(filesLoaded.map(f => basename(f.path)));
  const projectDir = getProjectDir();

  const signals: ProjectSignal[] = [
    {
      check: () => existsSync(join(projectDir, 'package.json')),
      ruleName: 'build-required.md',
      description: 'Has package.json but no build-required rule',
    },
    {
      check: () => existsSync(join(projectDir, '.github', 'workflows')),
      ruleName: 'ci-workflows.md',
      description: 'Has GitHub Actions workflows',
    },
    {
      check: () => existsSync(join(projectDir, 'Dockerfile')) || existsSync(join(projectDir, 'docker-compose.yml')),
      ruleName: 'docker-conventions.md',
      description: 'Has Docker config but no docker-conventions rule',
    },
    {
      check: () => existsSync(join(projectDir, 'tsconfig.json')),
      ruleName: 'typescript-conventions.md',
      description: 'Has TypeScript config but no TS conventions rule',
    },
    {
      check: () => {
        try {
          const pkg = JSON.parse(readFileSync(join(projectDir, 'package.json'), 'utf8'));
          return !!(pkg.dependencies?.next || pkg.devDependencies?.next);
        } catch { return false; }
      },
      ruleName: 'nextjs-conventions.md',
      description: 'Uses Next.js but no Next.js conventions rule',
    },
    {
      check: () => existsSync(join(projectDir, 'src', 'hooks')),
      ruleName: 'hot-path-hooks.md',
      description: 'Has hooks directory but no hot-path-hooks rule',
    },
  ];

  const missing: string[] = [];

  for (const signal of signals) {
    try {
      if (signal.check() && !loadedNames.has(signal.ruleName)) {
        missing.push(`${signal.ruleName} — ${signal.description}`);
      }
    } catch {
      // Skip failing checks
    }
  }

  if (missing.length === 0) return null;

  logHook(HOOK_NAME, `Smart suggestions: ${missing.length} rules could be added`);

  const top = missing.slice(0, 3);
  return `[Rule Suggestions] Consider creating these .claude/rules/ files:\n${top.map(m => `  - ${m}`).join('\n')}`;
}
